param([string]$OutPath="ENGREMIAT_MEMORY/operative/dashboard/dashboard-state.json")
$ErrorActionPreference="Stop"
[Console]::OutputEncoding=[System.Text.Encoding]::UTF8
function ED($p){if($p -and !(Test-Path -LiteralPath $p)){New-Item -ItemType Directory -Path $p -Force|Out-Null}}
function LJ($p){$a=@();if(Test-Path -LiteralPath $p -PathType Leaf){foreach($l in Get-Content -LiteralPath $p -Encoding UTF8){if([string]::IsNullOrWhiteSpace($l)){continue};try{$a+=($l|ConvertFrom-Json)}catch{}}};return @($a)}
$events=LJ "ENGREMIAT_MEMORY/operative/events/events.jsonl";$registry=LJ "data/registry/artifact-registry.jsonl";$gates=@();if(Test-Path -LiteralPath "data/gates"){$gates=Get-ChildItem -LiteralPath "data/gates" -Recurse -File -ErrorAction SilentlyContinue};$readiness="UNKNOWN";$activeObjective="ENGREMIAT_DEV_VISUAL_MEMORY_OPERATIVE_002";$activeStage="E03";$next="E04_COMMAND_HUB_Y_FLUJO_HUMANO";if(Test-Path -LiteralPath "data/dev/context-snapshot.json" -PathType Leaf){try{$ctx=Get-Content -LiteralPath "data/dev/context-snapshot.json" -Raw -Encoding UTF8|ConvertFrom-Json;if($ctx.objective_id){$activeObjective=[string]$ctx.objective_id};if($ctx.active_stage){$activeStage=[string]$ctx.active_stage};if($ctx.readiness.current_percent){$readiness=[string]$ctx.readiness.current_percent};if($ctx.next.action){$next=[string]$ctx.next.action}}catch{}}
$lastOk=@($events|Where-Object{$_.status -eq "OK"}|Select-Object -Last 8);$lastIssue=@($events|Where-Object{$_.status -eq "ERR" -or $_.status -eq "NO_GO"}|Select-Object -Last 8);$maps=@("ENGREMIAT_MEMORY/logseq/pages/Home.md","ENGREMIAT_MEMORY/maps/OPERATIVE_OVERVIEW.md","ENGREMIAT_MEMORY/maps/GATES_MAP.md","ENGREMIAT_MEMORY/maps/WORKERS_MAP.md","ENGREMIAT_MEMORY/maps/ERRORS_MAP.md","ENGREMIAT_MEMORY/maps/DECISIONS_MAP.md");$state=[ordered]@{objective_id="ENGREMIAT_DEV_VISUAL_MEMORY_OPERATIVE_002";stage_id="E03";status="OK";active_objective=$activeObjective;active_stage=$activeStage;readiness=$readiness;events_count=$events.Count;gates_count=@($gates).Count;artifacts_count=$registry.Count;last_ok=@($lastOk);last_issue=@($lastIssue);maps=$maps;next=$next;updated_at=(Get-Date).ToString("s");external_network=$false;dashboard_html="ENGREMIAT_MEMORY/dashboard/memory/index.html"};ED (Split-Path -Parent $OutPath);$state|ConvertTo-Json -Depth 100|Set-Content -LiteralPath $OutPath -Encoding UTF8;Write-Host ("OK dashboard_data=True events="+$events.Count+" gates="+@($gates).Count+" artifacts="+$registry.Count+" output="+$OutPath)
